package io.mockk.impl.recording.states

import io.mockk.MockKException
import io.mockk.impl.recording.CommonCallRecorder

class StubbingState(
    recorder: CommonCallRecorder,
) : RecordingState(recorder) {
    override fun recordingDone(): CallRecordingState {
        checkMissingCalls()
        return recorder.factories.stubbingAwaitingAnswerState(recorder)
    }

    private fun checkMissingCalls() {
        if (recorder.calls.isEmpty()) {
            throw MockKException(
                "Missing mocked calls inside every { ... } block: make sure the object inside the block is a mock " +
                    "\nNote: if you tried to stub a Kotlin inline function, it cannot be mocked. " +
                    "Inline functions are inlined at call sites, so no call is recorded. " +
                    "Extract a non-inline wrapper or mock the dependencies used inside the inline function.",
            )
        }
    }
}

try {
    val jwtVerifier = verifier(token)
    if (jwtVerifier == null) {
        JWTLogger.debug("JWT authentication failed: Unable to create JWT verifier")
        context.bearerChallenge(AuthenticationFailedCause.InvalidCredentials, realm, schemes, challengeFunction)
        return
    }

    val principal = verifyAndValidate(call, jwtVerifier, token, schemes, authenticationFunction)
    if (principal != null) {
        context.principal(name, principal)
        return
    }

    JWTLogger.debug("JWT authentication failed: Invalid credentials")
    context.bearerChallenge(
        AuthenticationFailedCause.InvalidCredentials,
        realm,
        schemes,
        challengeFunction
    )
} catch (cause: Throwable) {
    val message = cause.message ?: cause.javaClass.simpleName
    JWTLogger.debug("JWT authentication failed: $message", cause)
    context.error(JWTAuthKey, AuthenticationFailedCause.Error(message))
}

do {
            val currentIndex = index // it is important to read index every time
            if (currentIndex == interceptors.size) {
                if (!direct) {
                    resumeRootWith(Result.success(subject))
                    return false
                }

                return true
            }

            index = currentIndex + 1 // it is important to increase it before function invocation
            val next = interceptors[currentIndex]

            try {
                val result = pipelineStartCoroutineUninterceptedOrReturn(next, this, subject, continuation)
                if (result === COROUTINE_SUSPENDED) return false
            } catch (cause: Throwable) {
                resumeRootWith(Result.failure(cause))
                return false
            }
        } while (true)

if (index != null && isDirectory) {
    respondStaticFile(
        File(requestedFile, index),
        compressedTypes,
        contentType,
        cacheControl,
        lastModified,
        etag,
        modify
    )
} else if (!isDirectory) {
    if (checkExclude(requestedFile)) return

    respondStaticFile(requestedFile, compressedTypes, contentType, cacheControl, lastModified, etag, modify)
    if (isHandled) return
    for (extension in extensions) {
        val fileWithExtension = File("${requestedFile.path}.$extension")
        if (checkExclude(fileWithExtension)) return
        respondStaticFile(fileWithExtension, compressedTypes, contentType, cacheControl, lastModified, etag, modify)
        if (isHandled) return
    }
}

for (catchClause in expression.catchClauses) {
    val parameter = catchClause?.catchParameter ?: continue
    if (parameter.isCancellationExceptionOrSuperClass()) {
        // This could be a CancellationException - we should make sure that it gets explicitly
        // re-thrown upwards immediately
        val wasRethrownAtStart = catchClause.exceptionWasRethrown(parameter) &&
            !catchClause.doesAnythingElseBeforeRethrowing()
        if (
            !wasRethrownAtStart &&
            !catchClause.exceptionWasCheckedAndEnsureActiveCalled(parameter)
        ) {
            report(catchClause)
        }

        return // Only need to analyse the first CancellationException superclass instance
    }
}

if (!packageName.isRoot) {
    val rootPackageName = FqName(rootPackage)
    if (requireRootInDeclaration && !packageName.startsWith(rootPackageName)) {
        directive.reportInvalidPackageDeclaration("The package declaration is missing the root package")
        return
    }

    val normalizedFilePath = directive.containingKtFile.absolutePath().parent.toNormalizedForm()
    val expectedPath = packageName.withoutPrefix(rootPackageName).toNormalizedForm()

    val isInRootPackage = expectedPath.isEmpty()
    if (!isInRootPackage && !normalizedFilePath.endsWith("|$expectedPath")) {
        directive.reportInvalidPackageDeclaration(
            "The package declaration does not match the actual file location."
        )
    }
}

while (position < descriptor.elementsCount) {
    val name = descriptor.getTag(position++)
    val index = position - 1
    forceNull = false

    if (name in value || setForceNull(descriptor, index)) {
        // if forceNull is true, then decodeNotNullMark returns false and `null` is automatically inserted
        // by Decoder.decodeIfNullable
        if (!configuration.coerceInputValues) return index

        if (json.tryCoerceValue(
                descriptor, index,
                { currentElementOrNull(name) is JsonNull },
                { (currentElementOrNull(name) as? JsonPrimitive)?.contentOrNull },
                { // an unknown enum value should be coerced to null via decodeNotNullMark if explicitNulls=false :
                    if (setForceNull(descriptor, index)) return index
                }
            )
        ) continue // do not read coerced value

        return index
    }
}

while (currentPosition < descriptor.elementsCount) {
    val name = descriptor.getTag(currentPosition++)
    val index = currentPosition - 1
    forceNull = false

    if (hasName(name) || setForceNull(descriptor, index)) {
        // if forceNull is true, then decodeNotNullMark returns false and `null` is automatically inserted
        // by Decoder.decodeIfNullable
        if (!json.configuration.coerceInputValues) return index

        if (json.tryCoerceValue(
                descriptor, index,
                { getByTag(name) == null },
                { getByTag(name) as? String },
                { // an unknown enum value should be coerced to null via decodeNotNullMark if explicitNulls=false :
                    if (setForceNull(descriptor, index)) return index
                }
            )
        ) continue // do not read coerced value

        return index
    }
}

if (target.wasmTargetType != null) {
    // Kotlin/Wasm uses ES module system to depend on skiko through skiko.mjs.
    // Further bundler could process all files by its own (both skiko.mjs and skiko.wasm) and then emits its own version.
    // So that’s why we need to provide skiko.mjs and skiko.wasm only for webpack, but not in the final dist.
    compilation.binaries.all {
        it.linkSyncTask.configure {
            it.dependsOn(processSkikoRuntimeForKWasm)
            it.from.from(processedRuntimeDir)
        }
    }
} else {
    // Kotlin/JS depends on Skiko through global space.
    // Bundler cannot know anything about global externals, so that’s why we need to copy it to final dist
    project.tasks.named(compilation.processResourcesTaskName, ProcessResources::class.java) {
        it.from(unpackedRuntimeDir)
        it.dependsOn(unpackRuntime)
        it.exclude("META-INF")
    }
}

try {
    input.setReadListener(this)
    if (input.isFinished) {
        // setting read listener on already completed stream could cause it to hang
        // it is not by Servlet API spec but it actually works like this
        // it is relatively dangerous to touch isFinished due to async processing
        // if the servlet container call us onAllDataRead then it we will close events again that is safe
        events.close()
        return
    }
    awaitEvent() ?: return
    loop(buffer)

    events.close()
    channel.close()
} catch (cause: Throwable) {
    onError(cause)
} finally {
    @Suppress("BlockingMethodInNonBlockingContext")
    input.close() // ServletInputStream is in non-blocking mode
    ArrayPool.recycle(buffer)
}

try {
    val ctor = type.constructors.first()
    val args =
        ctor.javaConstructor
            ?.parameters
            ?.map { cache[it.type.kotlin] }
            ?.toTypedArray()
            ?: emptyArray()
    ctor.call(*args)
} catch (ex: InvocationTargetException) {
    // Current JUnit5 implementation resolves test constructor parameters one-by-one in order of declaration.
    // This means that any parameter can only access preceding arguments and only those can be used to
    // construct non-mock class instance. Breaking this order will cause NPE at test class initialization.
    // Same limitation also applies to spies as their use original class implementation under hood.
    throw MockKException(
        "Unable to instantiate class ${type.simpleName}. " +
            "Please ensure that all dependencies needed by class are defined before it in test class constructor. " +
            "Already registered mocks: ${cache.values}",
        ex,
    )
}

if (dataBuildersSourcesBaseTaskProvider != null) {
  val dataBuildersDirectoryConnection = DefaultDirectoryConnection(
      project = project,
      agp = agpOrNull,
      task = dataBuildersSourcesBaseTaskProvider,
      outputDir = dataBuildersSourcesBaseTaskProvider.flatMap {
        it.dataBuildersOutputDirectory()
      },
      hardCodedOutputDir = dataBuildersOutputDir(project, service),
      wiredWith = { it.dataBuildersOutputDirectory() }
  )

  if (service.dataBuildersOutputDirAction == null) {
    service.dataBuildersOutputDirAction = defaultDataBuildersOutputDirAction
  }
  service.dataBuildersOutputDirAction!!.execute(dataBuildersDirectoryConnection)
  generateApolloSources.configure {
    it.dependsOn(dataBuildersDirectoryConnection.task)
  }
}

when (it) {
  is OperationComplete -> {
    false
  }

  is ConnectionReEstablished -> {
    // means we are in the process of restarting the connection
    false
  }

  is NetworkError -> {
    emit(it)
    false
  }

  is GeneralError -> {
    // The server sends an error without an operation id. This happens when sending an unknown message type
    // to https://apollo-fullstack-tutorial.herokuapp.com/ for an example. In that case, this error is not fatal
    // and the server will continue honouring other subscriptions, so we just filter the error out and log it.
    println("Received general error while executing operation ${request.operation.name()}: ${it.payload}")
    true
  }

  else -> {
    emit(it)
    true
  }
}
